async-error-handling:
const riskyOperation = () => Promise.reject(new Error('Network failed'));
async function safeOperation() {
    try {
        const data = await riskyOperation();
        return data;
    } catch (error) {
        return 'fallback';
    }
}
return await safeOperation();

